import React, {useEffect, useState} from 'react'
import ReactPlayer from "react-player";
import Modal from 'react-modal';
import { useLocation } from 'react-router-dom';
import webproject1 from '../resources/web-project-1.png';
import SoftwareProjects from "./projects/SoftwareProjects";
const customStyles = {
    content : {
        top                   : '50%',
        left                  : '50%',
        right                 : 'auto',
        bottom                : 'auto',
        marginRight           : '-50%',
        transform             : 'translate(-50%, -50%)',
        width:"90%",
        height:"60%"
    }
};
const config =
    [
        {
            projectTitle:"Helicopter Simulation",
            projectURL:"https://youtu.be/qxyVnWaRFz8",
            languageUsed:"C++ and OpenGL",
            repoURL:"https://github.com/DMZnoo/Helicopter",
            button:"demo1",
            style:customStyles
        },
        {
            projectTitle:"Solar System Simulation",
            projectURL:"https://youtu.be/osDyGag0H-E",
            languageUsed:"C++ and OpenGL",
            repoURL:"https://github.com/DMZnoo/Solar_System",
            button:"demo2",
            style:customStyles
        }
    ];
const Projects = () => {
    const [isShown, SetIsShown] = useState({
        proj1:false,
        proj2:false
    });
    const [isPlayable,SetPlayable] = useState({
        proj1:false,
        proj2:false
    });

    const [modalIsOpen,setIsOpen] = useState({
        proj1:false,
        proj2:false
    });


    function detectMouse(n)
    {
        SetIsShown(n);
        SetPlayable(n);
    }
    function closeModal(modalN){
        SetIsShown({
            [modalN]:true
        });
        SetPlayable({
            [modalN]:true
        });
        setIsOpen({
            [modalN]:false
        });
    }
    const location = useLocation();
    const [isProfession,SetProfession] = useState("");
    useEffect(()=>{
        SetProfession(location.state.prof);
    },[location]);


    return(
        <div className="ui center aligned segment" id="project">
            <div className="ui centered grid">
                <SoftwareProjects config={config[0]}/>
                <SoftwareProjects config={config[1]}/>
            </div>
        </div>
    );
};
export default Projects;
